var surah064 = {
  number: 64,
  nameArabic: "at-Taghabun",
  nameEnglish: "At-Taghabun",
  meaning: "Mutual Disillusion",
  totalAyahs: 18,
  ayahs: [
    { number: 1, arabic: "يُسَبِّحُ لِلَّهِ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ لَهُ ٱلْمُلْكُ وَلَهُ ٱلْحَمْدُ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Yusabbihu lillahi ma fee alssamawati wama fee alardi lahu almulku walahu alhamdu wahuwa AAala kulli shayin qadeerun", transliterationB: "Yusabbihu lillaahi maa fis samaawaati wa maa fil ardi lahul mulku wa lahul hamd, wa Huwa 'alaa kulli shai 'in Qadeer", english: "Whatever is in the heavens and on earth, doth declare the Praises and Glory of Allah: to Him belongs dominion, and to Him belongs praise: and He has power over all things", romanUrdu: "Allah ki tasbeeh kar rahi hai har woh cheez jo aasmano mein hai aur har woh cheez jo zameen mein hai usi ki baadshahi hai aur usi ke liye tareef hai aur woh har cheez par qadir hai" },
    { number: 2, arabic: "هُوَ ٱلَّذِى خَلَقَكُمْ فَمِنكُمْ كَافِرٌۭ وَمِنكُم مُّؤْمِنٌۭ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ", transliteration: "Huwa allathee khalaqakum faminkum kafirun waminkum muminun waAllahu bima taAAmaloona baseerun", transliterationB: "Huwal lazee khalaqakum faminkum kaafirunw wa min kum mu'min ; wallaahu bimaa ta'maloona Baseer", english: "It is He Who has created you; and of you are some that are Unbelievers, and some that are Believers: and Allah sees well all that ye do", romanUrdu: "Wahi hai jisne tumko paida kiya, phir tum mein se koi kafir hai aur koi momin. Aur Allah woh sab kuch dekh raha hai jo tum karte ho" },
    { number: 3, arabic: "خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ وَصَوَّرَكُمْ فَأَحْسَنَ صُوَرَكُمْ ۖ وَإِلَيْهِ ٱلْمَصِيرُ", transliteration: "Khalaqa alssamawati waalarda bialhaqqi wasawwarakum faahsana suwarakum wailayhi almaseeru", transliterationB: "Khalaqas samaawaati wal arda bilhaqqi wa sawwarakum fa ahsana suwarakum wa ilaihil maseer", english: "He has created the heavens and the earth in just proportions, and has given you shape, and made your shapes beautiful: and to Him is the final Goal", romanUrdu: "Usne zameen aur aasmano ko barhaqq paida kiya hai, aur tumhari surat banayi aur badi umdah (excellent) banayi hai, aur usi ki taraf aakhir-e-kaar tumhein palatna hai" },
    { number: 4, arabic: "يَعْلَمُ مَا فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَيَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَ ۚ وَٱللَّهُ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "YaAAlamu ma fee alssamawati waalardi wayaAAlamu ma tusirroona wama tuAAlinoona waAllahu AAaleemun bithati alssudoori", transliterationB: "Ya'lamu maa fis samaawaati wal ardi wa ya'lamu maa tusirroona wa maa tu'linoon; wallaahu 'Aleemum bizaatis sudoor", english: "He knows what is in the heavens and on earth; and He knows what ye conceal and what ye reveal: yea, Allah knows well the (secrets) of (all) hearts", romanUrdu: "Zameen aur aasmano ki har cheez ka usey ilm hai jo kuch tum chupatey ho aur jo kuch tum zaahir karte ho sab us ko maloom hai. Aur woh dilon ka haal tak jaanta hai" },
    { number: 5, arabic: "أَلَمْ يَأْتِكُمْ نَبَؤُا۟ ٱلَّذِينَ كَفَرُوا۟ مِن قَبْلُ فَذَاقُوا۟ وَبَالَ أَمْرِهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Alam yatikum nabao allatheena kafaroo min qablu fathaqoo wabala amrihim walahum AAathabun aleemun", transliterationB: "Alam yaatikum naba'ul lazeena kafaroo min qablu fazaaqoo wabaala amrihim wa lahum 'azaabun aleem", english: "Has not the story reached you, of those who rejected Faith aforetime? So they tasted the evil result of their conduct; and they had a grievous Penalty", romanUrdu: "kya tumhein un logon ki koi khabar nahi pahunchi jinhon ne issey pehle kufar kiya aur phir apni shamat-e-aamaal (evil consequence) ka maza chakkh liya? aur aagey unke liye ek dardnaak azaab hai" },
    { number: 6, arabic: "ذَٰلِكَ بِأَنَّهُۥ كَانَت تَّأْتِيهِمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَقَالُوٓا۟ أَبَشَرٌۭ يَهْدُونَنَا فَكَفَرُوا۟ وَتَوَلَّوا۟ ۚ وَّٱسْتَغْنَى ٱللَّهُ ۚ وَٱللَّهُ غَنِىٌّ حَمِيدٌۭ", transliteration: "Thalika biannahu kanat tateehim rusuluhum bialbayyinati faqaloo abasharun yahdoonana fakafaroo watawallaw waistaghna Allahu waAllahu ghaniyyun hameedun", transliterationB: "Zaalika bi annahoo kaanat taateehim Rusuluhum bilbaiyinaati faqaaloo a basharuny yahdoonanaa fakafaroo wa tawallaw; wastaghnal laah; wallaahu ghaniyyun hameed", english: "That was because there came to them messengers with Clear Signs, but they said: \"Shall (mere) human beings direct us?\" So they rejected (the Message) and turned away. But Allah can do without (them): and Allah is free of all needs, worthy of all praise", romanUrdu: "Is anjaam ke mustahiq woh is liye huey ke unke paas unke Rasool khuli khuli daleelein (clear signs) aur nishaniyan lekar aate rahey, magar unhon ne kaha\" kya Insan humein hadayat deinge ?\" Is tarah unhon ne maanne se inkaar kardiya aur mooh pheir liya. Tab Allah bhi unsey be-parwa ho gaya aur Allah to hai hi be niyaz aur apni zaat mein aap Mahmood (Praiseworthy)" },
    { number: 7, arabic: "زَعَمَ ٱلَّذِينَ كَفَرُوٓا۟ أَن لَّن يُبْعَثُوا۟ ۚ قُلْ بَلَىٰ وَرَبِّى لَتُبْعَثُنَّ ثُمَّ لَتُنَبَّؤُنَّ بِمَا عَمِلْتُمْ ۚ وَذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌۭ", transliteration: "ZaAAama allatheena kafaroo an lan yubAAathoo qul bala warabbee latubAAathunna thumma latunabbaonna bima AAamiltum wathalika AAala Allahi yaseerun", transliterationB: "Za'amal lazeena kafarooo al-lany yub'asoo; qul balaa wa rabbee latub'asunna summa latunabba'unna bimaa 'amiltum; wa zaalika 'alal laahi yaseer", english: "The Unbelievers think that they will not be raised up (for Judgment). Say: \"Yea, By my Lord, Ye shall surely be raised up: then shall ye be told (the truth) of all that ye did. And that is easy for Allah", romanUrdu: "Munkireen ne badey dawey se kaha hai ke woh marne ke baad hargiz dobara na uthaye jayenge. Insey kaho\" nahin, mere Rubb ki kasam tum zaroor uthaye jaogey, phir zaroor tumhein bataya jayega ke tumne (duniya mein) kya kuch kiya hai aur aisa karna Allah ke liye bahut aasaan hai" },
    { number: 8, arabic: "فَـَٔامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَٱلنُّورِ ٱلَّذِىٓ أَنزَلْنَا ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌۭ", transliteration: "Faaminoo biAllahi warasoolihi waalnnoori allathee anzalna waAllahu bima taAAmaloona khabeerun", transliterationB: "Fa-aaminoo billaahi wa rasoolihee wannooril lazeee anzalnaa; wallaahu bima ta'maloona khabeer", english: "Believe, therefore, in Allah and His Messenger, and in the Light which we have sent down. And Allah is well acquainted with all that ye do", romanUrdu: "Pas iman lao Allah par, aur uske Rasool par, aur us roshni par jo humne nazil ki hai. Jo kuch tum karte ho Allah usse bakhabar hai" },
    { number: 9, arabic: "يَوْمَ يَجْمَعُكُمْ لِيَوْمِ ٱلْجَمْعِ ۖ ذَٰلِكَ يَوْمُ ٱلتَّغَابُنِ ۗ وَمَن يُؤْمِنۢ بِٱللَّهِ وَيَعْمَلْ صَٰلِحًۭا يُكَفِّرْ عَنْهُ سَيِّـَٔاتِهِۦ وَيُدْخِلْهُ جَنَّٰتٍۢ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَٰرُ خَٰلِدِينَ فِيهَآ أَبَدًۭا ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ", transliteration: "Yawma yajmaAAukum liyawmi aljamAAi thalika yawmu alttaghabuni waman yumin biAllahi wayaAAmal salihan yukaffir AAanhu sayyiatihi wayudkhilhu jannatin tajree min tahtiha alanharu khalideena feeha abadan thalika alfawzu alAAatheemu", transliterationB: "Ywma yajma'ukum li yawmil jam'i zaalika yawmut taghaabun; wa many-yumim billaahi wa ya'mal saalihany yukaffir 'anhu sayyi aatihee wa yudkhilhu jannaatin tajree min tahtihal anhaaru khaalideena feehaaa abadaa; zaalikal fawzul 'azeem", english: "The Day that He assembles you (all) for a Day of Assembly,- that will be a Day of mutual loss and gain (among you), and those who believe in Allah and work righteousness,- He will remove from them their ills, and He will admit them to Gardens beneath which Rivers flow, to dwell therein for ever: that will be the Supreme Achievement", romanUrdu: "(Iska pata tumhein us roz chal jayega ) jab ijtima (will assemble you )ke din woh tum sabko ikattha karega. Woh din hoga ek dusre ke muqable mein logon ki haar jeet ka. Jo Allah par iman laya hai aur neik amal karta hai, Allah uske gunah jhaad dega aur usey aisi jannaton mein daakhil karega jinke nichey nehrein behti hongi. Yeh log hamesha hamesha inmein rahenge. Yahi badi kamiyabi hai" },
    { number: 10, arabic: "وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ خَٰلِدِينَ فِيهَا ۖ وَبِئْسَ ٱلْمَصِيرُ", transliteration: "Waallatheena kafaroo wakaththaboo biayatina olaika ashabu alnnari khalideena feeha wabisa almaseeru", transliterationB: "Wallazeena kafaroo wa kazzaboo bi aayaaatinaaa ulaaa'ika ashaabun naari khaalideena feehaa bi'sal maseer", english: "But those who reject Faith and treat Our Signs as falsehoods, they will be Companions of the Fire, to dwell therein for aye: and evil is that Goal", romanUrdu: "Aur jin logon ne kufr kiya hai aur hamari aayaat ko jhutlaya hai woh dozakh ke bashindey(inmates ) honge, jismein woh hamesha rahenge. Aur woh badhtareen thikana hai" },
    { number: 11, arabic: "مَآ أَصَابَ مِن مُّصِيبَةٍ إِلَّا بِإِذْنِ ٱللَّهِ ۗ وَمَن يُؤْمِنۢ بِٱللَّهِ يَهْدِ قَلْبَهُۥ ۚ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۭ", transliteration: "Ma asaba min museebatin illa biithni Allahi waman yumin biAllahi yahdi qalbahu waAllahu bikulli shayin AAaleemun", transliterationB: "Maaa asaaba mim musee batin illaa bi-iznil laah; wa many yu'mim billaahi yahdi qalbah; wallaahu bikulli shai;in Aleem", english: "No kind of calamity can occur, except by the leave of Allah: and if any one believes in Allah, (Allah) guides his heart (aright): for Allah knows all things", romanUrdu: "Koi museebat kabhi nahi aati magar Allah ke izan(Allah’s leave) hi se aati hai. Jo shakhs Allah par iman rakhta ho Allah uske dil ko hidayat bakshta hai. Aur Allah ko har cheez ka ilm hai" },
    { number: 12, arabic: "وَأَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ ۚ فَإِن تَوَلَّيْتُمْ فَإِنَّمَا عَلَىٰ رَسُولِنَا ٱلْبَلَٰغُ ٱلْمُبِينُ", transliteration: "WaateeAAoo Allaha waateeAAoo alrrasoola fain tawallaytum fainnama AAala rasoolina albalaghu almubeenu", transliterationB: "Wa atee'ul laaha wa atee'ur Rasool; fa in tawallaitum fa innamaa 'alaa Rasoolinal balaaghul mubeen", english: "So obey Allah, and obey His Messenger: but if ye turn back, the duty of Our Messenger is but to proclaim (the Message) clearly and openly", romanUrdu: "Allah ki itaat karo aur Rasool ki itaat karo lekin agar tum itaat se mooh moadtey ho to hamarey Rasool par saaf saaf haqq pahuncha dene ke siwa koi zimmedari nahin hai" },
    { number: 13, arabic: "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ", transliteration: "Allahu la ilaha illa huwa waAAala Allahi falyatawakkali almuminoona", transliterationB: "Allaahu laaa ilaaha illaa Hoo; wa 'alal laahi falyata wakkalil mu'minoon", english: "Allah! There is no god but He: and on Allah, therefore, let the Believers put their trust", romanUrdu: "Allah woh hai jiske siwa koi khuda nahin, lihaza iman laney walon ko Allah hi par bharosa rakhna chahiye" },
    { number: 14, arabic: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ مِنْ أَزْوَٰجِكُمْ وَأَوْلَٰدِكُمْ عَدُوًّۭا لَّكُمْ فَٱحْذَرُوهُمْ ۚ وَإِن تَعْفُوا۟ وَتَصْفَحُوا۟ وَتَغْفِرُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌۭ رَّحِيمٌ", transliteration: "Ya ayyuha allatheena amanoo inna min azwajikum waawladikum AAaduwwan lakum faihtharoohum wain taAAfoo watasfahoo wataghfiroo fainna Allaha ghafoorun raheemun", transliterationB: "Yaaa ayyuhal lazeena aamanooo inna min azwaaji kum wa awlaadikum 'aduwwal lakum fahzaroohum; wa in ta'foo wa tasfahoo wa taghfiroo fa innal laaha ghafoorur Raheem", english: "O ye who believe! Truly, among your wives and your children are (some that are) enemies to yourselves: so beware of them! But if ye forgive and overlook, and cover up (their faults), verily Allah is Oft-Forgiving, Most Merciful", romanUrdu: "Aey logon jo iman laye ho, tumhari biwiyon aur tumhari aulad mein se baaz tumhare dushman hain, Inse hoshiyar raho. Aur agar tum Affu-o-darguzar(forgive and overlook) se kaam lo aur maaf kardo to Allah gafoor-o-Raheem hai" },
    { number: 15, arabic: "إِنَّمَآ أَمْوَٰلُكُمْ وَأَوْلَٰدُكُمْ فِتْنَةٌۭ ۚ وَٱللَّهُ عِندَهُۥٓ أَجْرٌ عَظِيمٌۭ", transliteration: "Innama amwalukum waawladukum fitnatun waAllahu AAindahu ajrun AAatheemun", transliterationB: "Innamaa amwaalukum wa awlaadukum fitnah; wallaahu 'indahooo ajrun 'azeem", english: "Your riches and your children may be but a trial: but in the Presence of Allah, is the highest, Reward", romanUrdu: "Tumhare maal aur tumhari aulad to ek aazmaish hai, aur Allah hi hai jiske paas bada ajar hai" },
    { number: 16, arabic: "فَٱتَّقُوا۟ ٱللَّهَ مَا ٱسْتَطَعْتُمْ وَٱسْمَعُوا۟ وَأَطِيعُوا۟ وَأَنفِقُوا۟ خَيْرًۭا لِّأَنفُسِكُمْ ۗ وَمَن يُوقَ شُحَّ نَفْسِهِۦ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Faittaqoo Allaha ma istataAAtum waismaAAoo waateeAAoo waanfiqoo khayran lianfusikum waman yooqa shuhha nafsihi faolaika humu almuflihoona", transliterationB: "Fattaqul laaha mastat'tum wasma'oo wa atee'oo waanfiqoo khairal li anfusikum; wa many-yooqa shuha nafsihee fa-ulaaa'ika humul muflihoon", english: "So fear Allah as much as ye can; listen and obey and spend in charity for the benefit of your own soul and those saved from the covetousness of their own souls,- they are the ones that achieve prosperity", romanUrdu: "lihaza jahan tak tumhare bas mein ho Allah se darte raho, aur suno aur itaat karo, aur apne maal kharch karo, yeh tumhare hi liye behtar hai. Jo apne dil ki tanggi se mehfooz reh gaye bas wahi falaah paney waley hain" },
    { number: 17, arabic: "إِن تُقْرِضُوا۟ ٱللَّهَ قَرْضًا حَسَنًۭا يُضَٰعِفْهُ لَكُمْ وَيَغْفِرْ لَكُمْ ۚ وَٱللَّهُ شَكُورٌ حَلِيمٌ", transliteration: "In tuqridoo Allaha qardan hasanan yudaAAifhu lakum wayaghfir lakum waAllahu shakoorun haleemun", transliterationB: "In tuqridul laaha qardan hasanany yudd'ifhu lakum wa yaghfir lakum; wallaahu Shakoorun Haleem", english: "If ye loan to Allah, a beautiful loan, He will double it to your (credit), and He will grant you Forgiveness: for Allah is most Ready to appreciate (service), Most Forbearing", romanUrdu: "Agar tum Allah ko qarz-e-hasan do to woh tumhein kai guna (several fold) badha kar dega aur tumhare kasooron se dar guzar farmayega. Allah bada qadardaan aur burdbar (Most Forbearing) hai" },
    { number: 18, arabic: "عَٰلِمُ ٱلْغَيْبِ وَٱلشَّهَٰدَةِ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "AAalimu alghaybi waalshshahadati alAAazeezu alhakeemu", transliterationB: "Aalimul-Ghaibi wash-shahaadatil 'Azeezul Hakeem", english: "Knower of what is open, Exalted in Might, Full of Wisdom", romanUrdu: "Haazir aur gayab har cheez ko jaanta hai, zabardast (mighty) aur daana(Most Wise) hai" }
  ]
};
